// Nexus Knowledge Base Tool
// Full dataset from Excel (single source of truth)

const docs = [
{category:"pricing",title:"starter_plan",content:`Plan: Starter. Monthly price: $299. Annual price: $249 with 17% savings. Ideal for small teams starting integrations. Maximum integrations: 3. API calls per month: 10,000. Overage cost: $25 per 1,000 API calls. Support: Email support with 48 hour response. Sync frequency: Scheduled sync. Connectors tier: Standard. Webhooks: Basic. Field mapping: Standard. SSO: Not available. Audit logs: Basic activity logs. IP whitelisting: Not available. Dedicated account manager: No. Custom connectors: 0 per year. Onboarding: Community access. Free trial: 14 days. Cancel anytime: Yes.`},

{category:"pricing",title:"professional_plan",content:`Plan: Professional. Monthly price: $799. Annual price: $649 with 19% savings. Ideal for growing businesses. Maximum integrations: 10. API calls per month: 50,000. Overage cost: $20 per 1,000 API calls. Support: Email and phone support with 24 hour response. Sync frequency: Real-time every 5 minutes. Connectors tier: Standard and Premium connectors. Webhooks: Advanced with retry logic. Field mapping: Custom mapping supported. SSO: Not available. Audit logs: Basic logs. IP whitelisting: Not available.`},

{category:"pricing",title:"enterprise_plan",content:`Plan: Enterprise. Custom pricing starting around $2500+. Ideal for large organizations. Maximum integrations: Unlimited. API calls: 250,000+ starting limit. Support: 24/7 premium support with 4 hour response. Sync frequency: Real-time every 30 seconds. Connectors tier: All connectors including enterprise-exclusive connectors. Webhooks: Advanced with retry logic. Field mapping: Custom mapping supported. SSO: Supported with SAML 2.0. Audit logs: Comprehensive logs. IP whitelisting: Supported. Dedicated account manager: Yes. Custom connectors: Up to 2 per year.`},

{category:"pricing",title:"nonprofit_discount",content:`Nonprofit organizations receive 25% discount on annual Nexus subscriptions.`},

{category:"setup",title:"integration_setup",content:`Nexus integrates platforms such as Salesforce, HubSpot, SAP, and Microsoft Dynamics. Setup: Click Connect Integration, authorize platform, ensure admin permissions and API access enabled.`},

{category:"setup",title:"real_time_sync",content:`Enterprise sync: about 30 seconds using webhooks. Professional sync: about 5 minutes.`},

{category:"setup",title:"manual_sync",content:`Manual sync allows users to trigger synchronization manually instead of waiting for scheduled intervals.`},

{category:"setup",title:"scheduled_sync",content:`Scheduled sync runs periodically at configured intervals rather than real-time.`},

{category:"security",title:"encryption",content:`Nexus encrypts data both in transit and at rest using industry standard encryption protocols.`},

{category:"security",title:"soc2_compliance",content:`Nexus is SOC2 compliant and follows strict security controls.`},

{category:"security",title:"gdpr_compliance",content:`Nexus complies with GDPR regulations for protecting EU personal data.`},

{category:"security",title:"hipaa_availability",content:`HIPAA compliance available only for Enterprise customers with signed Business Associate Agreement.`},

{category:"security",title:"sso_support",content:`Single Sign-On using SAML 2.0 supported for Enterprise customers.`},

{category:"security",title:"ip_whitelisting",content:`IP whitelisting available for Enterprise customers.`},

{category:"security",title:"audit_logs",content:`Nexus provides audit logs tracking integration activities.`},

{category:"security",title:"soc2_report_request",content:`SOC2 audit reports available under NDA upon request.`},

{category:"escalate_support",title:"technical_support",content:`Integration failures, authentication errors, sync issues should be escalated to user@example.com.`},

{category:"escalate_support",title:"integration_failure",content:`If integration fails repeatedly escalate to Nexus support team.`},

{category:"escalate_sales",title:"enterprise_sales",content:`Enterprise pricing requests, partnerships and custom integrations escalate to user@example.com.`},

{category:"escalate_sales",title:"partnership_requests",content:`Partnership inquiries should be escalated to the Nexus sales department.`},

{category:"escalate_legal",title:"contract_review",content:`Legal agreements and contract related questions escalate to user@example.com.`},

{category:"hr",title:"careers",content:`Job applications or career inquiries should be directed to HR team user@example.com.`},

{category:"spam",title:"spam_email",content:`Promotional or malicious emails should be marked as spam and ignored.`},

{category:"misdirected",title:"wrong_recipient",content:`Emails unrelated to Nexus should be marked as misdirected and optionally replied with a wrong recipient message.`}
];

// input from AI agent
const category = $json.category || "";

// filter docs for that category
const filtered = docs.filter(d => d.category === category);

// full context
const full_context = docs.map(d => `[${d.category}] ${d.title}: ${d.content}`).join("\n\n");

// category context
const category_context = filtered.map(d => `${d.title}: ${d.content}`).join("\n\n");

return {
category,
category_context,
full_context
};
